import sys
import math

def is_palindrome(s):
    return s == s[::-1]

def generate_palindrome(n):
    # Try to generate a palindrome string that evaluates to n
    # We'll try different lengths and structures
    for length in range(1, 11):  # Limit to small lengths for performance
        for i in range(1, 10):
            # Try a string with a single digit
            s = str(i) * length
            if is_palindrome(s):
                try:
                    val = int(s)
                    if val == n:
                        return s
                except:
                    pass

        # Try a string with multiplication
        for i in range(1, 10):
            for j in range(1, 10):
                for k in range(1, 10):
                    # Try a string like i*j*k*i
                    s = str(i) + '*' + str(j) + '*' + str(k) + '*' + str(i)
                    if is_palindrome(s):
                        try:
                            val = eval(s)
                            if val == n:
                                return s
                        except:
                            pass

        # Try a string with more multiplications
        for i in range(1, 10):
            for j in range(1, 10):
                for k in range(1, 10):
                    for l in range(1, 10):
                        # Try a string like i*j*k*l*i
                        s = str(i) + '*' + str(j) + '*' + str(k) + '*' + str(l) + '*' + str(i)
                        if is_palindrome(s):
                            try:
                                val = eval(s)
                                if val == n:
                                    return s
                            except:
                                pass

    return "-1"

def main():
    N = int(sys.stdin.readline())
    result = generate_palindrome(N)
    print(result)

if __name__ == "__main__":
    main()
